import java.sql.*;

public class SQLInjectionSecure {
    public static void main(String[] args) {
        try {
            // Simulating user input (this should ideally come from user input)
            String userInput = "'; DROP TABLE users; --";

            // Constructing the SQL query with a Prepared Statement
            String query = "SELECT * FROM users WHERE username = ?";

            // Establishing database connection and executing the query
            Connection conn = DriverManager.getConnection("jdbc:mysql://localhost:3306/mydatabase", "username", "password");
            PreparedStatement pstmt = conn.prepareStatement(query);
            pstmt.setString(1, userInput);

            ResultSet rs = pstmt.executeQuery();

            // Processing the results
            while (rs.next()) {
                System.out.println("User found: " + rs.getString("username"));
            }

        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}

